 {"id":"franken_numpy-r6lj","title":"Reframe Bayesian decision engine claim in README to loss-minimization with posterior estimation","status":"closed","priority":3,"issue_type":"docs","created_at":"2026-04-06T21:36:57.347437819Z","created_by":"ubuntu","updated_at":"2026-04-06T21:43:06.191164391Z","closed_at":"2026-04-06T21:43:06.190892947Z","close_reason":"Reframed to risk-aware decision engine in README and FEATURE_PARITY","source_repo":".","compaction_level":0,"original_size":0,"comments":[{"id":14,"issue_id":"franken_numpy-r6lj","author":"ubuntu","text":"README L224 calls the runtime decision system a Bayesian decision engine. The implementation uses a loss model with prior odds and posterior probability calculation, which has Bayesian flavor. But calling it Bayesian overstates the sophistication. Consider reframing to 'loss-minimization decision system with posterior risk estimation' or simply 'risk-aware decision engine'. The detailed description in README L226-245 is accurate — its just the headline term.","created_at":"2026-04-06T21:39:17Z"}]}
 {"id":"franken_numpy-r6se","title":"numpy.full_like python wrapper parity","description":"Add fnp_python.full_like passthrough wrapper around numpy.full_like(a, fill_value, dtype=None, order='K', subok=True, shape=None, *, device=None). Include oracle test covering: default dtype/order inherited from input, explicit dtype override, shape override, scalar and object fill values, subclass/subok surface parity, and zero-sized input behavior.","status":"open","priority":2,"issue_type":"task","created_at":"2026-04-21T07:48:24Z","created_by":"ubuntu","updated_at":"2026-04-21T07:48:24Z","source_repo":".","compaction_level":0,"original_size":0}
